-- Enrichment marathon batch: Boxbot, BoxyHQ, Bradfield School of Computer Science, Braid, Brainboard, Braintrust, Branch, BreakTimer

-- ── Boxbot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boxbot is a supply chain automation company based in Alameda, California, that builds AI-driven storage and retrieval systems for parcel logistics. Founded in 2016 by Austin Oehlerking and Mark Godwin, the company originally set out to build autonomous last-mile delivery trucks, but pivoted in 2023 after discovering stronger customer demand for its box-handling robotics technology. Boxbot's core product, the Boxbot Operating System (BOS), turns ordinary conveyors into three-dimensional, AI-optimized storage systems using proprietary trays and a modular, gantry-based architecture that can reach up to 25 feet in height. The system is designed to roughly double storage density versus static shelving while maintaining 99.9 percent uptime, handling items from small padded envelopes up to 75-pound parcels at throughput rates from 250 to over 4,000 pieces per hour. Boxbot sells to last-mile parcel carriers, third-party logistics providers, airports and air cargo operators, industrial facilities, and retailers that need dense, dynamic buffering and sortation without expanding their physical footprint. The company has raised roughly 29.5 million dollars in venture funding, including a 12 million dollar Series A led by Playground Global with participation from Maersk Growth and Toyota Ventures.$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise quote (B2B hardware-plus-software deployment; no public pricing)$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed - contact sales for a custom quote$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Small venture-backed startup; exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Alameda, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Boxbot Review: AI Robotic Storage and Sortation for Logistics$q$, seo_title),
  seo_meta_description = COALESCE($q$Boxbot turns conveyors into 3D robotic storage for parcel carriers, 3PLs, and airports. See how the Boxbot Operating System works, who it serves, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boxbot is a robotics and supply-chain automation company headquartered in Alameda, California. It was founded in 2016 by Austin Oehlerking and Mark Godwin, initially as a stealth autonomous last-mile delivery truck startup competing in the self-driving van space. During customer conversations, the team found that prospects were far more excited about a secondary box-handling and storage robot the company had built than about the self-driving trucks themselves. In 2023 Boxbot formally pivoted around that signal, becoming a company focused entirely on robotic storage and retrieval for parcels, and announced a 12 million dollar Series A led by Playground Global with participation from Maersk Growth, Toyota Ventures, and Pear Ventures, bringing total disclosed funding to roughly 29.5 million dollars. Boxbot's flagship offering is the Boxbot Operating System (BOS), an AI software layer paired with a modular, gantry-based hardware system that attaches to standard conveyor infrastructure. Rather than requiring a fully custom automated warehouse, Boxbot's approach retrofits the humble conveyor belt into a three-dimensional storage system: proprietary trays carry individual parcels up into a vertical gantry structure that can reach up to 25 feet, effectively turning flat floor space into dense, dynamically managed storage. The company claims roughly double the storage density of static shelving, 99.9 percent uptime, and full-stack sensor fusion for fault avoidance and monitoring. On the throughput side, Boxbot's systems are built to handle a wide range of parcel sizes, from about 6 by 6 by 1 inches and 1 pound up to 35 by 24 by 24 inches and 75 pounds, at rates from 250 to more than 4,000 pieces per hour depending on configuration. Target customers include last-mile parcel carriers looking to buffer and stage packages at delivery stations, third-party logistics (3PL) operators needing cross-dock buffering, airports and air cargo/bonded storage facilities, industrial sites, and retailers that want automated counter retrieval for click-and-collect or returns. Because Boxbot sells a combined hardware-and-software system rather than a subscription SaaS product, it does not publish pricing; deployments are quoted and engineered per facility, which is typical for industrial robotics vendors. Boxbot is a relatively young company in its current form - its parcel-storage product line is only a few years old following the 2023 pivot - so its track record of large-scale, multi-year deployments is still being built, and it competes against larger, more established players such as GreyOrange, Addverb, and Unbox Robotics in the broader warehouse automation category. Prospective buyers evaluating Boxbot should expect an enterprise sales process, facility assessment, and integration planning rather than a self-serve signup, which is standard for this category of physical automation technology.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'abb96509-e0ba-4927-9110-f72512053172';

