-- ── BoxyHQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BoxyHQ is an open-source enterprise identity and security infrastructure company founded in August 2021 by Deepak Prabhakara and Carlos Samame, originally headquartered in London, United Kingdom. It built a suite of self-hostable, developer-first building blocks - most notably SAML Jackson for SAML and OIDC single sign-on, a SCIM 2.0 Directory Sync service for automated user provisioning and deprovisioning, and Retraced for audit logging - that let SaaS companies add enterprise-ready authentication and compliance features without building SSO plumbing from scratch. The tools are offered under open-source licenses for self-hosting, with a hosted or enterprise tier for teams that want a managed service, SLAs, and support. In May 2025, identity infrastructure company Ory acquired BoxyHQ, and BoxyHQ's product line has since been rebranded and continued as Ory Polis (SSO and Directory Sync) alongside Ory's broader identity platform, though the original open-source repositories remain available and are still maintained under the Ory organization.$q$, short_description),
  pricing_model = COALESCE($q$Open source (free, self-hosted) with a paid enterprise or managed tier$q$, pricing_model),
  starting_price = COALESCE($q$Free for self-hosted, open-source use; enterprise pricing is custom$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Small startup-scale team prior to its 2025 acquisition by Ory; exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Originally London, United Kingdom; now operating as part of Ory$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BoxyHQ Review: Open-Source SAML SSO and SCIM for SaaS Apps$q$, seo_title),
  seo_meta_description = COALESCE($q$BoxyHQ built open-source SAML SSO, SCIM Directory Sync, and audit logging for SaaS teams. See what it offers and how it became Ory Polis after Ory's 2025 acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BoxyHQ was founded in August 2021 by Deepak Prabhakara and Carlos Samame with a focused mission: help SaaS startups add the enterprise-grade authentication and compliance features that large customers demand, without each team having to build SAML SSO, directory sync, and audit logging from scratch. Its first and best-known product, SAML Jackson, wraps the notoriously fiddly SAML 2.0 and OpenID Connect protocols behind a simple OAuth 2.0-style flow, so developers can integrate enterprise SSO with a small amount of code rather than months of protocol work. On top of SSO, BoxyHQ built a SCIM 2.0-based Directory Sync service that lets enterprise customers automatically provision and deprovision user accounts and keep group membership in sync with their own identity provider in real time, and Retraced, an audit-log product that records and makes searchable the security-relevant events happening inside a customer's application. All three products could be run as a standalone self-hosted service or embedded via an npm library, and BoxyHQ maintained an admin portal for managing SSO, Directory Sync, and Audit Logs from a single interface, plus a Next.js-based 'SaaS Starter Kit' boilerplate to help teams bootstrap enterprise-ready applications faster. The open-source model meant BoxyHQ's code was broadly used and referenced across the developer community, with integrations into popular frameworks and auth libraries such as NextAuth.js/Auth.js. In May 2025, Ory - a larger identity and access management company - acquired BoxyHQ, describing the deal as a way to help enterprises modernize identity management and move away from monolithic identity providers. Following the acquisition, BoxyHQ's flagship SSO and Directory Sync products were rebranded as Ory Polis, and the GitHub organization now carries a 'BoxyHQ (acquired by Ory)' label, with active development continuing under the Ory brand (for example, the ory/polis repository). Retraced and other BoxyHQ-branded tools have similarly been folded into Ory's product and blog content. For a directory listing in 2026, it's important to be precise: 'BoxyHQ' as an independent company effectively no longer exists as a separate go-to-market entity - the technology, team, and roadmap now live inside Ory. Teams evaluating this technology today will most likely interact with it as Ory Polis, Ory Directory Sync, or a related Ory product, even though the open-source repositories and much of the developer-facing branding still carry the BoxyHQ name in places. Anyone researching 'BoxyHQ' should treat it as the historical and technical foundation of what is now part of Ory's identity platform rather than as an actively marketed standalone product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f0206b22-b8e1-4aea-b694-687c1d876d1b';

