-- ── Bradfield School of Computer Science ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bradfield School of Computer Science was a San Francisco-based, in-person and live-online school that taught practicing software engineers the foundational computer science they typically missed - algorithms and data structures, computer architecture, networking, operating systems, databases, and distributed systems - through small, discussion-based classes rather than video lectures. Founded and run by instructor Oz Nova starting around the mid-2010s, Bradfield built a reputation in the Bay Area tech community for rigorous, textbook-and-paper-driven courses aimed at mid-career engineers who wanted to deepen their CS fundamentals rather than learn a new framework. Over roughly eight years of operation the school taught more than 1,000 students, offering both standalone courses (such as Computer Architecture, Deep Learning for Engineers, and Engineering Leadership) and a flagship 12-month, part-time live-online CS fundamentals program. In 2023, Nova put Bradfield's live cohort courses on indefinite hiatus once the final cohorts finished, redirecting his effort into CS Primer, a self-paced platform designed to make the best parts of Bradfield's curriculum more affordable and accessible. Bradfield is not currently enrolling new live cohorts.$q$, short_description),
  pricing_model = COALESCE($q$Historically tuition-based (per-course and program fees); currently not enrolling$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable - live courses are on indefinite hiatus as of 2023$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Very small, founder-led school with a roster of specialist instructors, not a large institution$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bradfield School of Computer Science Review: Status, Courses and CS Primer$q$, seo_title),
  seo_meta_description = COALESCE($q$Bradfield School of Computer Science taught mid-career engineers CS fundamentals in San Francisco. Learn what it offered, why it's on hiatus, and where its curriculum lives now.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bradfield School of Computer Science was an unusual entrant in the tech-education landscape: rather than teaching people how to code or use a specific framework, it taught practicing software engineers the underlying computer science concepts - algorithms and data structures, computer architecture, networking, operating systems, databases, and distributed systems - that many self-taught or bootcamp-trained engineers never formally studied. The school was founded and run out of San Francisco by instructor Oz Nova starting around 2015, and over roughly eight years it built a strong reputation within the Bay Area engineering community for its rigorous, discussion-based teaching style. Classes were intentionally small and combined tutorials, hands-on programming exercises, textbook study, and reading of primary research papers, a format closer to a graduate seminar than a coding bootcamp or a MOOC. Bradfield's course catalog included both standalone offerings - for example, Computer Architecture, Deep Learning for Engineers (taught by Dr. Brian Spiering), and an Engineering Leadership course (taught by Xavier Shay) - and its flagship program, a 12-month, part-time, live-online curriculum designed for mid-career software engineers who wanted to accelerate their technical depth without leaving their jobs. Students could historically attend in person in San Francisco or join live online, and over its run the school taught more than 1,000 students. In 2023, after eight years of running live cohorts, Oz Nova decided to put Bradfield's live-course offerings on indefinite hiatus once the then-current cohorts finished. In his own account, the decision wasn't driven by the school failing - curriculum and brand recognition had both improved year over year - but by a personal calculation about where he could have the most impact with his limited time and energy. Rather than continuing to scale a live, instructor-intensive model, Nova redirected his focus to CS Primer, a self-paced platform intended to preserve the best parts of the Bradfield curriculum and philosophy while making it more affordable and accessible to a much wider, asynchronous audience. As of the time of this research, Bradfield's website exists in a largely archival state, and the school is not accepting new live-cohort enrollments; anyone interested in the same style of rigorous computer science education is directed toward CS Primer instead. Because there are no active pricing plans or intake process, this profile should be read as an accurate historical and reference entry for the school's teaching philosophy and legacy rather than a live product listing that visitors can currently sign up for.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '424eeed7-a359-4785-947f-0867babfff58';

