-- ── Braid ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$'Braid' refers to the open protocol and research project hosted at braid.org, which extends HTTP from a state-transfer protocol into a full state-synchronization protocol. Led by Michael Toomim and developed collaboratively through an open working group and the IETF standards process (draft-toomim-httpbis-braid-http), Braid adds versioning, subscriptions (real-time updates on GET requests), patches (fine-grained updates via Range Requests), and merge-types (so servers can declare how conflicting edits should be resolved, for example via CRDTs or operational transforms) to ordinary HTTP. The goal is to let any web resource stay synchronized across multiple clients, servers, and proxies, enabling collaborative, offline-capable, local-first, and peer-to-peer web applications without every team having to build a bespoke real-time sync layer. Note that 'Braid' is an ambiguous name in software: this profile covers the braid.org state-synchronization protocol specifically, not GitHub's now-defunct 'git braid' submodule tool, not unrelated chat or messaging products sometimes called Braid, and not any commercial company of the same name. Braid is a non-commercial, open, community-maintained specification and reference-implementation ecosystem rather than a SaaS product or company.$q$, short_description),
  pricing_model = COALESCE($q$Not applicable - a free, open specification and open-source reference implementations$q$, pricing_model),
  starting_price = COALESCE($q$Free / open source$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not applicable - a volunteer-driven open working group, not a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable - distributed open-source project; lead maintainer Michael Toomim is based in the San Francisco Bay Area$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Braid (braid.org) Explained: The HTTP State Synchronization Protocol$q$, seo_title),
  seo_meta_description = COALESCE($q$Braid extends HTTP into a state synchronization protocol for real-time, local-first web apps. Learn what braid.org is, how it works, and how it differs from other tools named Braid.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Braid, as hosted at braid.org, is not a company or a commercial SaaS product - it is an open protocol and research project focused on a single, hard problem: HTTP was designed to transfer a snapshot of a resource's state from server to client, but the modern web increasingly needs resources to stay synchronized in real time across many clients, servers, and proxies, with support for concurrent edits, offline use, and peer-to-peer topologies. Rather than asking every team to invent a bespoke real-time sync layer on top of HTTP (as most collaborative apps do today, using WebSockets, custom polling, or proprietary backend services), Braid proposes extending HTTP itself with a small number of well-defined additions. The core specification, often referred to as Braid-HTTP and formalized as an IETF Internet-Draft (draft-toomim-httpbis-braid-http), adds four capabilities: versioning of HTTP resources, so clients and servers can refer to specific states of a resource over time; subscriptions on GET requests, so a client can ask to be notified of updates rather than polling; patches delivered through an extension of HTTP's existing Range Request mechanism, allowing fine-grained partial updates instead of re-sending an entire resource; and merge-types, which let a resource declare how simultaneous, conflicting writes should be reconciled - for example using a CRDT (conflict-free replicated data type) or an operational transform algorithm. Put together, these four pieces let an ordinary web resource behave like a shared, live document: any client can read it, subscribe to changes, write to it concurrently with other clients, and trust that the server (or peer) will merge those changes according to a well-defined algorithm, all while remaining compatible with existing HTTP infrastructure like caches and proxies. Braid is led by Michael Toomim and developed through an open, transparent process: contributors meet biweekly, discuss on public mailing lists and GitHub, and move the specification forward using the IETF's 'rough consensus' model rather than a single vendor's roadmap. Around the core protocol, an ecosystem of reference implementations and demo applications has grown up, including Braid-HTTP server/client libraries, Braid-Text (a CRDT-based collaborative text implementation), a Braid-Chrome browser extension, Braidfs (a filesystem-level sync tool), and small demonstration apps such as Peery View, the peer-to-peer chat app Quiet, the collaborative code-editing tool Ethersync, and Braidmail. Related open-source sync engines and CRDT libraries in the surrounding ecosystem - such as Diamond Types, Sync9, CR-SQLite, Redwood, and Statebus - are frequently discussed alongside Braid, though they are separate projects with their own maintainers. Because it is an open specification rather than a product, Braid has no pricing, account system, or company behind it; anyone can implement it, and there is no vendor lock-in. At the same time, it remains an evolving Internet-Draft rather than a finalized, universally adopted standard, so production use requires real engineering investment and a tolerance for a still-maturing spec. Given how common the name 'Braid' is in software - it has also been used for GitHub's discontinued Git submodule tool and for various unrelated messaging or collaboration products - anyone researching this entry should confirm they mean the braid.org state-synchronization protocol specifically.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '013fc84f-ffdf-4d76-8166-cf81a411c2e8';

