INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Boxbot Operating System (BOS)$q$, $q$An AI software layer that makes real-time decisions about item placement and retrieval to maximize storage density and throughput across a facility.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Three-dimensional conveyor storage$q$, $q$Proprietary trays convert standard, flat conveyor infrastructure into vertical, addressable storage without requiring a fully custom warehouse build.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Modular gantry architecture$q$, $q$A scalable, gantry-based structure that can reach up to 25 feet in height, letting facilities add storage density within an existing footprint.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Wide item-size handling$q$, $q$Systems handle parcels ranging from roughly 6 by 6 by 1 inches and 1 pound up to 35 by 24 by 24 inches and 75 pounds.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$High-throughput sortation$q$, $q$Configurable throughput from about 250 up to more than 4,000 pieces per hour depending on facility needs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Full-stack sensor fusion$q$, $q$Integrated sensing across the system for real-time monitoring and proactive fault avoidance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$99.9 percent uptime design target$q$, $q$Engineering aimed at minimizing downtime for continuous, high-volume parcel operations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Hands-free load and unload$q$, $q$Automated load/unload interfaces designed to reduce manual handling at delivery stations and distribution points.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abb96509-e0ba-4927-9110-f72512053172', $q$Significant storage density gains without expanding a facility's physical footprint$q$, 0);
