INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Loop AI assistant$q$, $q$A natural-language-driven assistant that analyzes production traces, generates evaluation datasets, and recommends custom scorers.$q$, 3);
