INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$What does Braintrust (braintrust.dev) do?$q$, $q$Braintrust is an AI observability and evaluation platform that helps teams trace LLM applications and AI agents in production, run offline evaluations, and catch quality regressions before they reach users.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Is Braintrust the same company as usebraintrust.com?$q$, $q$No. Braintrust (braintrust.dev) is an AI observability platform founded in 2023 by Ankur Goyal. Braintrust (usebraintrust.com) is an unrelated blockchain-based freelance talent marketplace founded in 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Who founded Braintrust (braintrust.dev)?$q$, $q$Braintrust was founded in 2023 by Ankur Goyal, who previously founded Impira, a data management company acquired by Figma.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$How much does Braintrust cost?$q$, $q$Braintrust offers a free Starter plan, a Pro plan starting at $249 per month, and custom Enterprise pricing for larger deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$What is Loop in Braintrust?$q$, $q$Loop is Braintrust's AI assistant for evaluation development, which can analyze production traces and generate datasets and scorers from natural-language instructions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$What is Brainstore?$q$, $q$Brainstore is Braintrust's purpose-built data store designed for fast queries across millions of nested AI agent traces.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$What languages and SDKs does Braintrust support?$q$, $q$Braintrust provides SDKs for Python, TypeScript, Go, Ruby, and C#, and works with any model or AI framework.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Who are Braintrust's customers?$q$, $q$Braintrust's customers include Notion, Stripe, Vercel, Airtable, Instacart, Zapier, Ramp, Dropbox, Cloudflare, and BILL.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Evaluating and regression-testing LLM prompts and models$q$, $q$AI and ML engineers use Braintrust's evaluation framework to compare prompts and models against datasets before shipping changes.$q$, $q$AI and machine learning engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Tracing and debugging production AI agents$q$, $q$Platform and backend engineering teams use Braintrust's tracing to inspect agent reasoning steps and tool calls in production.$q$, $q$Platform and backend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Building human-in-the-loop quality review workflows$q$, $q$AI product and QA teams use Braintrust's scoring tools to combine automated and human review of AI output quality.$q$, $q$AI product and QA teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Starter$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["$10 monthly credits for Topics plus token rates","1 GB processed data ($4/GB overage)","10,000 scores included ($2.50 per 1,000 overage)","14-day data retention","Unlimited users, projects, datasets, playgrounds, and experiments","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Pro$q$, $q$$249$q$, $q$monthly$q$, NULL, $q$["$249 monthly credits for Topics plus token rates","5 GB processed data ($3/GB overage)","50,000 scores included ($1.50 per 1,000 overage)","30-day data retention ($0.50/GB/month after)","Custom charts, environments, and RBAC","Priority support and unlimited Loop agent access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Custom data retention and export, including S3 export","Full RBAC implementation","On-prem or hosted deployment options","SAML SSO, BAA, DPA, and SLA guarantees","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$braintrust-evalfirst$q$, $q$Braintrust's Eval-First Approach to AI Quality$q$, 2, ARRAY[$q$Most software observability tools were built around a 'log everything, search later' model that works well for deterministic systems where a bug either exists or doesn't. LLM-powered products are different: the same prompt can produce subtly different, sometimes wrong, sometimes brilliant outputs, and 'quality' is often a matter of degree rather than pass/fail. Braintrust's founding premise is that teams building AI products need to start from defining what a good output looks like - through datasets, scoring criteria, and explicit test cases - and then measure every change against that definition, rather than discovering quality problems only after users complain.$q$, $q$This eval-first philosophy shapes the whole product: the evaluation framework lets teams run experiments against real datasets, compare prompts and models side by side, and score results using LLM-based graders, code-based scorers, or human review, so that a prompt or model change can be validated before it ships rather than debugged after the fact in production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$braintrust-platform$q$, $q$Tracing, Loop, and Brainstore: How the Platform Fits Together$q$, 2, ARRAY[$q$Evaluation alone isn't enough once an AI product is live, so Braintrust also provides production tracing: the ability to inspect every request, tool call, and reasoning step an AI agent takes, search across millions of logs, and track latency, cost, and quality metrics in real time. This closes the loop between what a team tested before shipping and what's actually happening with real users.$q$, $q$Two more specialized pieces extend this further. Loop is Braintrust's AI assistant for evaluation development - a team can describe, in natural language, a failure mode they want to investigate, and Loop will analyze the relevant production traces, generate an evaluation dataset around that failure, and recommend custom scorers to catch it going forward. Brainstore is the underlying data infrastructure making all of this fast at scale: a data store purpose-built for AI workloads, designed to support quick queries across millions of nested agent traces and high-cardinality observability data, which general-purpose logging databases are not well suited to handle.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4780ba32-7996-4e79-bff8-bb8b30ce99d3', $q$braintrust-disambiguation$q$, $q$A Note on the Other Braintrust$q$, 2, ARRAY[$q$Anyone researching 'Braintrust' should be aware that the name is shared by two unconnected companies. Braintrust (braintrust.dev), covered in this profile, is the San Francisco-based AI observability and evaluation platform founded by Ankur Goyal in 2023. Braintrust (usebraintrust.com) is a separate, blockchain-based freelance talent marketplace founded in San Jose in 2018 by Adam Jackson, Gabriel Luna-Ostaseski, and Brian Flynn, which connects vetted technical and design freelancers with enterprise clients and uses a BTRST token to distribute network governance and incentives to its community of contributors.$q$, $q$The two companies operate in entirely different markets - one is developer infrastructure for AI quality, the other is a hiring and freelance marketplace - and share no corporate relationship. Given how similar the names and even some of the branding language ('Braintrust,' talent, quality) can look at a glance, it's worth double-checking which Braintrust a source, article, or job posting is actually referring to before drawing conclusions.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e431b41f-c262-4a08-8527-8e08946e3c29', $q$Deep linking across install states$q$, $q$Routes users from ads, email, SMS, and social directly into in-app content, handling thousands of device and platform edge cases including deferred deep linking.$q$, 0);
